// Find all HalcyonEventsV2_CL records related to a specific HalcyonAlertId.
// Replace <HalcyonAlertId> with the HalcyonAlertId from a Halcyon Alert.
let TargetAlertId = "<HalcyonAlertId>";
HalcyonEventsV2_CL
| extend HalcyonAlertId = tostring(unmapped.halcyon_alert_id)
| where HalcyonAlertId == TargetAlertId
| order by TimeGenerated desc
